-- Web Empire 800 Tools Program — Production Wave 4
-- Adds 100 deterministic formula tools across 10 new categories.
-- Safe, idempotent upserts. No destructive deletes.

begin;

insert into public.categories(
  slug, name_ar, name_en, description, icon, style_key, sort_order, is_active
)
values
  ('home-tools', 'أدوات المنزل', 'Home Tools', 'حاسبات الكهرباء والمياه والمساحات والتكاليف المنزلية.', 'home', 'violet', 400, true),
  ('retail-tools', 'أدوات التجزئة', 'Retail Tools', 'حاسبات المبيعات والمخزون والخصومات وأداء الفروع.', 'store', 'gold', 410, true),
  ('manufacturing-tools', 'أدوات التصنيع', 'Manufacturing Tools', 'حاسبات الإنتاج والهدر والجودة والطاقة التشغيلية.', 'factory', 'cyan', 420, true),
  ('project-management-tools', 'أدوات إدارة المشاريع', 'Project Management Tools', 'حاسبات الميزانية والإنجاز والموارد والجدول الزمني.', 'kanban', 'violet', 430, true),
  ('hospitality-tools', 'أدوات الضيافة والفنادق', 'Hospitality Tools', 'حاسبات الإشغال والإيرادات والتشغيل وخدمة الغرف.', 'hotel', 'gold', 440, true),
  ('insurance-tools', 'أدوات التأمين', 'Insurance Tools', 'حاسبات الأقساط والتغطية والمطالبات والتكلفة.', 'shield-check', 'green', 450, true),
  ('energy-tools', 'أدوات الطاقة', 'Energy Tools', 'حاسبات الاستهلاك والطلب والطاقة الشمسية والتكلفة.', 'zap', 'cyan', 460, true),
  ('cybersecurity-tools', 'أدوات الأمن السيبراني', 'Cybersecurity Tools', 'حاسبات المخاطر والحوادث والتغطية والامتثال التشغيلي.', 'shield', 'violet', 470, true),
  ('photography-tools', 'أدوات التصوير', 'Photography Tools', 'حاسبات التخزين والتسعير والتعريض والإنتاج.', 'camera', 'gold', 480, true),
  ('fitness-tools', 'أدوات اللياقة', 'Fitness Tools', 'حاسبات التدريب والمسافة والطاقة والإنجاز الرياضي العام.', 'activity', 'green', 490, true)
on conflict (slug) do update set
  name_ar = excluded.name_ar,
  name_en = excluded.name_en,
  description = excluded.description,
  icon = excluded.icon,
  style_key = excluded.style_key,
  sort_order = excluded.sort_order,
  is_active = true;

insert into public.category_translations(category_id, locale_id, name, description)
select category.id, locale.id, seed.name, seed.description
from (
  values
    ('home-tools', 'ar', 'أدوات المنزل', 'حاسبات الكهرباء والمياه والمساحات والتكاليف المنزلية.'),
    ('home-tools', 'en', 'Home Tools', 'حاسبات الكهرباء والمياه والمساحات والتكاليف المنزلية.'),
    ('retail-tools', 'ar', 'أدوات التجزئة', 'حاسبات المبيعات والمخزون والخصومات وأداء الفروع.'),
    ('retail-tools', 'en', 'Retail Tools', 'حاسبات المبيعات والمخزون والخصومات وأداء الفروع.'),
    ('manufacturing-tools', 'ar', 'أدوات التصنيع', 'حاسبات الإنتاج والهدر والجودة والطاقة التشغيلية.'),
    ('manufacturing-tools', 'en', 'Manufacturing Tools', 'حاسبات الإنتاج والهدر والجودة والطاقة التشغيلية.'),
    ('project-management-tools', 'ar', 'أدوات إدارة المشاريع', 'حاسبات الميزانية والإنجاز والموارد والجدول الزمني.'),
    ('project-management-tools', 'en', 'Project Management Tools', 'حاسبات الميزانية والإنجاز والموارد والجدول الزمني.'),
    ('hospitality-tools', 'ar', 'أدوات الضيافة والفنادق', 'حاسبات الإشغال والإيرادات والتشغيل وخدمة الغرف.'),
    ('hospitality-tools', 'en', 'Hospitality Tools', 'حاسبات الإشغال والإيرادات والتشغيل وخدمة الغرف.'),
    ('insurance-tools', 'ar', 'أدوات التأمين', 'حاسبات الأقساط والتغطية والمطالبات والتكلفة.'),
    ('insurance-tools', 'en', 'Insurance Tools', 'حاسبات الأقساط والتغطية والمطالبات والتكلفة.'),
    ('energy-tools', 'ar', 'أدوات الطاقة', 'حاسبات الاستهلاك والطلب والطاقة الشمسية والتكلفة.'),
    ('energy-tools', 'en', 'Energy Tools', 'حاسبات الاستهلاك والطلب والطاقة الشمسية والتكلفة.'),
    ('cybersecurity-tools', 'ar', 'أدوات الأمن السيبراني', 'حاسبات المخاطر والحوادث والتغطية والامتثال التشغيلي.'),
    ('cybersecurity-tools', 'en', 'Cybersecurity Tools', 'حاسبات المخاطر والحوادث والتغطية والامتثال التشغيلي.'),
    ('photography-tools', 'ar', 'أدوات التصوير', 'حاسبات التخزين والتسعير والتعريض والإنتاج.'),
    ('photography-tools', 'en', 'Photography Tools', 'حاسبات التخزين والتسعير والتعريض والإنتاج.'),
    ('fitness-tools', 'ar', 'أدوات اللياقة', 'حاسبات التدريب والمسافة والطاقة والإنجاز الرياضي العام.'),
    ('fitness-tools', 'en', 'Fitness Tools', 'حاسبات التدريب والمسافة والطاقة والإنجاز الرياضي العام.')
) as seed(category_slug, locale_code, name, description)
join public.categories category on category.slug = seed.category_slug
join public.locales locale on locale.code = seed.locale_code
on conflict (category_id, locale_id) do update set
  name = excluded.name,
  description = excluded.description,
  updated_at = now();

create temporary table wave4_formula_tool_seed (
  category_slug text not null,
  slug text not null,
  title_ar text not null,
  title_en text not null,
  description_ar text not null,
  description_en text not null,
  runtime_config jsonb not null,
  input_fields jsonb not null,
  english_fields jsonb not null,
  submit_ar text not null,
  submit_en text not null,
  sort_order integer not null,
  is_featured boolean not null
) on commit drop;

insert into wave4_formula_tool_seed(
  category_slug, slug, title_ar, title_en, description_ar, description_en,
  runtime_config, input_fields, english_fields, submit_ar, submit_en,
  sort_order, is_featured
)
values
  ('home-tools', 'home-electricity-cost-calculator', 'حاسبة تكلفة كهرباء المنزل', 'Home Electricity Cost Calculator', 'قدّر تكلفة الكهرباء من الاستهلاك وسعر الكيلوواط.', 'Estimate home electricity cost.', '{"expression":"kwh * price_per_kwh","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الكهرباء","resultLabelEn":"Electricity cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"kwh","label":"الاستهلاك ك.و.س","type":"number","required":true,"step":0.01,"min":0},{"key":"price_per_kwh","label":"سعر الكيلوواط","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"kwh","label":"Consumption kWh","type":"number","required":true,"step":0.01,"min":0},{"key":"price_per_kwh","label":"Price per kWh","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4000, true),
  ('home-tools', 'water-bill-estimator', 'حاسبة فاتورة المياه', 'Water Bill Estimator', 'قدّر فاتورة المياه من الاستهلاك وسعر الوحدة.', 'Estimate water bill from usage.', '{"expression":"cubic_meters * price_per_cubic_meter","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"فاتورة المياه","resultLabelEn":"Water bill","decimals":2,"showEquation":true}'::jsonb, '[{"key":"cubic_meters","label":"الاستهلاك بالمتر المكعب","type":"number","required":true,"step":0.01,"min":0},{"key":"price_per_cubic_meter","label":"سعر المتر المكعب","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"cubic_meters","label":"Usage in cubic meters","type":"number","required":true,"step":0.01,"min":0},{"key":"price_per_cubic_meter","label":"Price per cubic meter","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4001, false),
  ('home-tools', 'air-conditioner-monthly-cost-calculator', 'حاسبة تكلفة المكيف شهريًا', 'Air Conditioner Monthly Cost Calculator', 'احسب تكلفة تشغيل المكيف شهريًا.', 'Calculate monthly AC operating cost.', '{"expression":"power_kw * hours_per_day * days * price_per_kwh","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"التكلفة الشهرية","resultLabelEn":"Monthly cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"power_kw","label":"قدرة المكيف بالكيلوواط","type":"number","required":true,"step":0.01,"min":0},{"key":"hours_per_day","label":"ساعات التشغيل يوميًا","type":"number","required":true,"step":0.01,"min":0,"max":24},{"key":"days","label":"عدد الأيام","type":"number","required":true,"step":1,"min":0,"defaultValue":30},{"key":"price_per_kwh","label":"سعر الكيلوواط","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"power_kw","label":"AC power kW","type":"number","required":true,"step":0.01,"min":0},{"key":"hours_per_day","label":"Hours per day","type":"number","required":true,"step":0.01,"min":0,"max":24},{"key":"days","label":"Days","type":"number","required":true,"step":1,"min":0,"defaultValue":30},{"key":"price_per_kwh","label":"Price per kWh","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4002, true),
  ('home-tools', 'room-paint-cost-calculator', 'حاسبة تكلفة دهان الغرفة', 'Room Paint Cost Calculator', 'قدّر تكلفة الدهان من المساحة والتغطية وسعر اللتر.', 'Estimate room paint cost.', '{"expression":"area * coats / coverage_per_liter * price_per_liter","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الدهان","resultLabelEn":"Paint cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"area","label":"المساحة م²","type":"number","required":true,"step":0.01,"min":0},{"key":"coats","label":"عدد الطبقات","type":"number","required":true,"step":1,"min":1,"defaultValue":2},{"key":"coverage_per_liter","label":"التغطية لكل لتر","type":"number","required":true,"step":0.01,"min":0.01},{"key":"price_per_liter","label":"سعر اللتر","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"area","label":"Area m²","type":"number","required":true,"step":0.01,"min":0},{"key":"coats","label":"Coats","type":"number","required":true,"step":1,"min":1,"defaultValue":2},{"key":"coverage_per_liter","label":"Coverage per liter","type":"number","required":true,"step":0.01,"min":0.01},{"key":"price_per_liter","label":"Price per liter","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4003, false),
  ('home-tools', 'flooring-cost-calculator', 'حاسبة تكلفة الأرضيات', 'Flooring Cost Calculator', 'احسب تكلفة الأرضيات مع نسبة الهدر.', 'Calculate flooring cost including waste.', '{"expression":"area * (1 + waste_rate / 100) * cost_per_sqm","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الأرضيات","resultLabelEn":"Flooring cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"area","label":"المساحة م²","type":"number","required":true,"step":0.01,"min":0},{"key":"waste_rate","label":"نسبة الهدر","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":10},{"key":"cost_per_sqm","label":"التكلفة لكل م²","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"area","label":"Area m²","type":"number","required":true,"step":0.01,"min":0},{"key":"waste_rate","label":"Waste rate","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":10},{"key":"cost_per_sqm","label":"Cost per m²","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4004, false),
  ('home-tools', 'home-cleaning-cost-calculator', 'حاسبة تكلفة تنظيف المنزل', 'Home Cleaning Cost Calculator', 'احسب تكلفة التنظيف حسب الساعات والسعر.', 'Calculate home cleaning cost.', '{"expression":"hours * hourly_rate","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة التنظيف","resultLabelEn":"Cleaning cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"hours","label":"عدد الساعات","type":"number","required":true,"step":0.01,"min":0},{"key":"hourly_rate","label":"سعر الساعة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"hours","label":"Hours","type":"number","required":true,"step":0.01,"min":0},{"key":"hourly_rate","label":"Hourly rate","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4005, false),
  ('home-tools', 'solar-payback-period-calculator', 'حاسبة فترة استرداد الطاقة الشمسية', 'Solar Payback Period Calculator', 'قدّر سنوات استرداد تكلفة النظام الشمسي.', 'Estimate solar system payback period.', '{"expression":"system_cost / annual_savings","outputUnitAr":" سنة","outputUnitEn":" years","resultLabelAr":"فترة الاسترداد","resultLabelEn":"Payback period","decimals":2,"showEquation":true}'::jsonb, '[{"key":"system_cost","label":"تكلفة النظام","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_savings","label":"التوفير السنوي","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"system_cost","label":"System cost","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_savings","label":"Annual savings","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 4006, false),
  ('home-tools', 'home-maintenance-budget-calculator', 'حاسبة ميزانية صيانة المنزل', 'Home Maintenance Budget Calculator', 'قدّر ميزانية الصيانة السنوية كنسبة من قيمة المنزل.', 'Estimate annual home maintenance budget.', '{"expression":"home_value * maintenance_rate / 100","outputUnitAr":" ر.س/سنة","outputUnitEn":" SAR/year","resultLabelAr":"ميزانية الصيانة","resultLabelEn":"Maintenance budget","decimals":2,"showEquation":true}'::jsonb, '[{"key":"home_value","label":"قيمة المنزل","type":"number","required":true,"step":0.01,"min":0},{"key":"maintenance_rate","label":"نسبة الصيانة","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":1}]'::jsonb, '[{"key":"home_value","label":"Home value","type":"number","required":true,"step":0.01,"min":0},{"key":"maintenance_rate","label":"Maintenance rate","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 4007, false),
  ('home-tools', 'appliance-usage-cost-calculator', 'حاسبة تكلفة تشغيل جهاز', 'Appliance Usage Cost Calculator', 'احسب تكلفة تشغيل جهاز لفترة محددة.', 'Calculate appliance usage cost.', '{"expression":"watts / 1000 * hours * price_per_kwh","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة التشغيل","resultLabelEn":"Usage cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"watts","label":"قدرة الجهاز بالواط","type":"number","required":true,"step":0.01,"min":0},{"key":"hours","label":"ساعات التشغيل","type":"number","required":true,"step":0.01,"min":0},{"key":"price_per_kwh","label":"سعر الكيلوواط","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"watts","label":"Appliance watts","type":"number","required":true,"step":0.01,"min":0},{"key":"hours","label":"Usage hours","type":"number","required":true,"step":0.01,"min":0},{"key":"price_per_kwh","label":"Price per kWh","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4008, false),
  ('home-tools', 'moving-cost-calculator', 'حاسبة تكلفة نقل الأثاث', 'Moving Cost Calculator', 'قدّر تكلفة النقل من المسافة وساعات العمل.', 'Estimate moving cost.', '{"expression":"distance * cost_per_km + labor_hours * labor_rate","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة النقل","resultLabelEn":"Moving cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"distance","label":"المسافة كم","type":"number","required":true,"step":0.01,"min":0},{"key":"cost_per_km","label":"التكلفة لكل كم","type":"number","required":true,"step":0.01,"min":0},{"key":"labor_hours","label":"ساعات العمل","type":"number","required":true,"step":0.01,"min":0},{"key":"labor_rate","label":"سعر ساعة العمالة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"distance","label":"Distance km","type":"number","required":true,"step":0.01,"min":0},{"key":"cost_per_km","label":"Cost per km","type":"number","required":true,"step":0.01,"min":0},{"key":"labor_hours","label":"Labor hours","type":"number","required":true,"step":0.01,"min":0},{"key":"labor_rate","label":"Labor hourly rate","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4009, false),
  ('retail-tools', 'retail-gross-margin-calculator', 'حاسبة هامش التجزئة', 'Retail Gross Margin Calculator', 'احسب هامش الربح الإجمالي للتجزئة.', 'Calculate retail gross margin.', '{"expression":"(sales - cost_of_goods) / sales * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"هامش الربح","resultLabelEn":"Gross margin","decimals":2,"showEquation":true}'::jsonb, '[{"key":"sales","label":"المبيعات","type":"number","required":true,"step":0.01,"min":0.01},{"key":"cost_of_goods","label":"تكلفة البضاعة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"sales","label":"Sales","type":"number","required":true,"step":0.01,"min":0.01},{"key":"cost_of_goods","label":"Cost of goods","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4010, true),
  ('retail-tools', 'sell-through-rate-calculator', 'حاسبة معدل البيع من المخزون', 'Sell-through Rate Calculator', 'احسب نسبة الوحدات المباعة من المخزون المتاح.', 'Calculate units sold as a percentage of available inventory.', '{"expression":"units_sold / units_available * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل البيع","resultLabelEn":"Sell-through rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"units_sold","label":"الوحدات المباعة","type":"number","required":true,"step":0.01,"min":0},{"key":"units_available","label":"الوحدات المتاحة","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"units_sold","label":"Units sold","type":"number","required":true,"step":0.01,"min":0},{"key":"units_available","label":"Units available","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 4011, false),
  ('retail-tools', 'retail-stockout-rate-calculator', 'حاسبة معدل نفاد المخزون', 'Stockout Rate Calculator', 'احسب نسبة مرات نفاد المخزون.', 'Calculate stockout frequency.', '{"expression":"stockout_events / demand_events * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل النفاد","resultLabelEn":"Stockout rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"stockout_events","label":"مرات النفاد","type":"number","required":true,"step":0.01,"min":0},{"key":"demand_events","label":"إجمالي طلبات المنتج","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"stockout_events","label":"Stockout events","type":"number","required":true,"step":0.01,"min":0},{"key":"demand_events","label":"Demand events","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 4012, false),
  ('retail-tools', 'retail-discount-impact-calculator', 'حاسبة أثر الخصم على الإيراد', 'Retail Discount Impact Calculator', 'احسب قيمة الخصم الإجمالية.', 'Calculate total discount amount.', '{"expression":"original_price * discount_rate / 100 * units","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"قيمة الخصم","resultLabelEn":"Discount value","decimals":2,"showEquation":true}'::jsonb, '[{"key":"original_price","label":"السعر الأصلي","type":"number","required":true,"step":0.01,"min":0},{"key":"discount_rate","label":"نسبة الخصم","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"units","label":"عدد الوحدات","type":"number","required":true,"step":1,"min":0}]'::jsonb, '[{"key":"original_price","label":"Original price","type":"number","required":true,"step":0.01,"min":0},{"key":"discount_rate","label":"Discount rate","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"units","label":"Units","type":"number","required":true,"step":1,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4013, false),
  ('retail-tools', 'sales-per-square-meter-calculator', 'حاسبة المبيعات لكل متر مربع', 'Sales per Square Meter Calculator', 'احسب مبيعات المتجر لكل متر مربع.', 'Calculate store sales per square meter.', '{"expression":"sales / store_area","outputUnitAr":" ر.س/م²","outputUnitEn":" SAR/m²","resultLabelAr":"المبيعات لكل متر مربع","resultLabelEn":"Sales per square meter","decimals":2,"showEquation":true}'::jsonb, '[{"key":"sales","label":"إجمالي المبيعات","type":"number","required":true,"step":0.01,"min":0},{"key":"store_area","label":"مساحة المتجر م²","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"sales","label":"Total sales","type":"number","required":true,"step":0.01,"min":0},{"key":"store_area","label":"Store area m²","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 4014, true),
