  ('photography-tools', 'photography-project-price-calculator', 'حاسبة سعر جلسة التصوير', 'Photography Project Price Calculator', 'احسب سعر المشروع من الساعات والتكاليف.', 'Calculate photography project price.', '{"expression":"shoot_hours * hourly_rate + editing_hours * editing_rate + fixed_cost","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"سعر المشروع","resultLabelEn":"Project price","decimals":2,"showEquation":true}'::jsonb, '[{"key":"shoot_hours","label":"ساعات التصوير","type":"number","required":true,"step":0.01,"min":0},{"key":"hourly_rate","label":"سعر ساعة التصوير","type":"number","required":true,"step":0.01,"min":0},{"key":"editing_hours","label":"ساعات التعديل","type":"number","required":true,"step":0.01,"min":0},{"key":"editing_rate","label":"سعر ساعة التعديل","type":"number","required":true,"step":0.01,"min":0},{"key":"fixed_cost","label":"تكاليف ثابتة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"shoot_hours","label":"Shoot hours","type":"number","required":true,"step":0.01,"min":0},{"key":"hourly_rate","label":"Shoot hourly rate","type":"number","required":true,"step":0.01,"min":0},{"key":"editing_hours","label":"Editing hours","type":"number","required":true,"step":0.01,"min":0},{"key":"editing_rate","label":"Editing hourly rate","type":"number","required":true,"step":0.01,"min":0},{"key":"fixed_cost","label":"Fixed cost","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4082, true),
  ('photography-tools', 'photo-print-cost-calculator', 'حاسبة تكلفة طباعة الصور', 'Photo Print Cost Calculator', 'احسب تكلفة الطباعة من الكمية وسعر النسخة.', 'Calculate photo print cost.', '{"expression":"prints * cost_per_print","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الطباعة","resultLabelEn":"Print cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"prints","label":"عدد النسخ","type":"number","required":true,"step":0.01,"min":0},{"key":"cost_per_print","label":"تكلفة النسخة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"prints","label":"Prints","type":"number","required":true,"step":0.01,"min":0},{"key":"cost_per_print","label":"Cost per print","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4083, false),
  ('photography-tools', 'camera-depreciation-calculator', 'حاسبة انخفاض قيمة الكاميرا', 'Camera Depreciation Calculator', 'قدّر قيمة الكاميرا بعد سنوات من الاستخدام.', 'Estimate camera value after depreciation.', '{"expression":"purchase_price * ((1 - annual_rate / 100) ^ years)","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"القيمة الحالية التقديرية","resultLabelEn":"Estimated current value","decimals":2,"showEquation":true}'::jsonb, '[{"key":"purchase_price","label":"سعر الشراء","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_rate","label":"نسبة الانخفاض السنوي","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"years","label":"عدد السنوات","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"purchase_price","label":"Purchase price","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_rate","label":"Annual depreciation rate","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"years","label":"Years","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4084, false),
  ('photography-tools', 'battery-shooting-time-calculator', 'حاسبة زمن التصوير بالبطاريات', 'Battery Shooting Time Calculator', 'قدّر مدة التصوير من عدد البطاريات.', 'Estimate shooting time from battery count.', '{"expression":"batteries * hours_per_battery","outputUnitAr":" ساعة","outputUnitEn":" hours","resultLabelAr":"مدة التصوير","resultLabelEn":"Shooting time","decimals":2,"showEquation":true}'::jsonb, '[{"key":"batteries","label":"عدد البطاريات","type":"number","required":true,"step":0.01,"min":0},{"key":"hours_per_battery","label":"الساعات لكل بطارية","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"batteries","label":"Batteries","type":"number","required":true,"step":0.01,"min":0},{"key":"hours_per_battery","label":"Hours per battery","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4085, false),
  ('photography-tools', 'image-aspect-ratio-width-calculator', 'حاسبة عرض الصورة حسب النسبة', 'Image Width from Aspect Ratio Calculator', 'احسب العرض من الارتفاع ونسبة العرض.', 'Calculate width from height and aspect ratio.', '{"expression":"height * aspect_width / aspect_height","outputUnitAr":" بكسل","outputUnitEn":" pixels","resultLabelAr":"العرض","resultLabelEn":"Width","decimals":0,"showEquation":true}'::jsonb, '[{"key":"height","label":"الارتفاع بالبكسل","type":"number","required":true,"step":0.01,"min":0},{"key":"aspect_width","label":"جزء العرض","type":"number","required":true,"step":0.01,"min":0.01},{"key":"aspect_height","label":"جزء الارتفاع","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"height","label":"Height pixels","type":"number","required":true,"step":0.01,"min":0},{"key":"aspect_width","label":"Aspect width","type":"number","required":true,"step":0.01,"min":0.01},{"key":"aspect_height","label":"Aspect height","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 4086, false),
