  ('fitness-tools', 'walking-distance-calculator', 'حاسبة مسافة المشي', 'Walking Distance Calculator', 'قدّر المسافة من الخطوات وطول الخطوة.', 'Estimate walking distance from steps.', '{"expression":"steps * step_length_meters / 1000","outputUnitAr":" كم","outputUnitEn":" km","resultLabelAr":"مسافة المشي","resultLabelEn":"Walking distance","decimals":2,"showEquation":true}'::jsonb, '[{"key":"steps","label":"عدد الخطوات","type":"number","required":true,"step":0.01,"min":0},{"key":"step_length_meters","label":"طول الخطوة بالمتر","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"steps","label":"Steps","type":"number","required":true,"step":0.01,"min":0},{"key":"step_length_meters","label":"Step length meters","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4090, true),
  ('fitness-tools', 'running-pace-calculator', 'حاسبة وتيرة الجري', 'Running Pace Calculator', 'احسب الدقائق لكل كيلومتر.', 'Calculate minutes per kilometer.', '{"expression":"total_minutes / distance_km","outputUnitAr":" دقيقة/كم","outputUnitEn":" min/km","resultLabelAr":"وتيرة الجري","resultLabelEn":"Running pace","decimals":2,"showEquation":true}'::jsonb, '[{"key":"total_minutes","label":"المدة بالدقائق","type":"number","required":true,"step":0.01,"min":0},{"key":"distance_km","label":"المسافة كم","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"total_minutes","label":"Total minutes","type":"number","required":true,"step":0.01,"min":0},{"key":"distance_km","label":"Distance km","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 4091, true),
  ('fitness-tools', 'cycling-speed-calculator', 'حاسبة سرعة ركوب الدراجة', 'Cycling Speed Calculator', 'احسب السرعة المتوسطة.', 'Calculate average cycling speed.', '{"expression":"distance_km / hours","outputUnitAr":" كم/س","outputUnitEn":" km/h","resultLabelAr":"السرعة المتوسطة","resultLabelEn":"Average speed","decimals":2,"showEquation":true}'::jsonb, '[{"key":"distance_km","label":"المسافة كم","type":"number","required":true,"step":0.01,"min":0},{"key":"hours","label":"المدة بالساعات","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"distance_km","label":"Distance km","type":"number","required":true,"step":0.01,"min":0},{"key":"hours","label":"Hours","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 4092, false),
  ('fitness-tools', 'workout-volume-calculator', 'حاسبة حجم التمرين', 'Workout Volume Calculator', 'احسب حجم تمرين المقاومة.', 'Calculate resistance training volume.', '{"expression":"sets * reps * weight","outputUnitAr":" كجم","outputUnitEn":" kg","resultLabelAr":"حجم التمرين","resultLabelEn":"Workout volume","decimals":2,"showEquation":true}'::jsonb, '[{"key":"sets","label":"عدد المجموعات","type":"number","required":true,"step":0.01,"min":0},{"key":"reps","label":"عدد التكرارات","type":"number","required":true,"step":0.01,"min":0},{"key":"weight","label":"الوزن","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"sets","label":"Sets","type":"number","required":true,"step":0.01,"min":0},{"key":"reps","label":"Reps","type":"number","required":true,"step":0.01,"min":0},{"key":"weight","label":"Weight","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 4093, false),
  ('fitness-tools', 'one-rep-max-estimator', 'حاسبة الحد الأقصى لتكرار واحد', 'One Rep Max Estimator', 'قدّر 1RM باستخدام الوزن والتكرارات.', 'Estimate one-rep max.', '{"expression":"weight * (1 + reps / 30)","outputUnitAr":" كجم","outputUnitEn":" kg","resultLabelAr":"الحد الأقصى التقديري","resultLabelEn":"Estimated one-rep max","decimals":2,"showEquation":true,"noteAr":"تقدير عام وليس توصية تدريبية فردية.","noteEn":"A general estimate, not individualized training advice."}'::jsonb, '[{"key":"weight","label":"الوزن المستخدم","type":"number","required":true,"step":0.01,"min":0},{"key":"reps","label":"عدد التكرارات","type":"number","required":true,"step":0.01,"min":1,"max":30}]'::jsonb, '[{"key":"weight","label":"Weight used","type":"number","required":true,"step":0.01,"min":0},{"key":"reps","label":"Reps","type":"number","required":true,"step":0.01,"min":1,"max":30}]'::jsonb, 'احسب النتيجة', 'Calculate', 4094, false),
  ('fitness-tools', 'weekly-training-load-calculator', 'حاسبة الحمل التدريبي الأسبوعي', 'Weekly Training Load Calculator', 'احسب الحمل من المدة والشدة.', 'Calculate training load from duration and intensity.', '{"expression":"duration_minutes * intensity_score","outputUnitAr":" نقطة","outputUnitEn":" points","resultLabelAr":"الحمل التدريبي","resultLabelEn":"Training load","decimals":2,"showEquation":true}'::jsonb, '[{"key":"duration_minutes","label":"مدة التدريب بالدقائق","type":"number","required":true,"step":0.01,"min":0},{"key":"intensity_score","label":"درجة الشدة","type":"number","required":true,"step":0.01,"min":0,"max":10}]'::jsonb, '[{"key":"duration_minutes","label":"Training duration minutes","type":"number","required":true,"step":0.01,"min":0},{"key":"intensity_score","label":"Intensity score","type":"number","required":true,"step":0.01,"min":0,"max":10}]'::jsonb, 'احسب النتيجة', 'Calculate', 4095, false),
  ('fitness-tools', 'calories-per-workout-estimator', 'حاسبة السعرات في التمرين', 'Workout Calories Estimator', 'قدّر السعرات من الوزن والمدة والمعامل.', 'Estimate workout calories.', '{"expression":"weight_kg * duration_hours * activity_factor","outputUnitAr":" سعرة","outputUnitEn":" kcal","resultLabelAr":"السعرات التقديرية","resultLabelEn":"Estimated calories","decimals":2,"showEquation":true,"noteAr":"تقدير عام وقد يختلف حسب الحالة الفردية.","noteEn":"A general estimate that may vary by individual."}'::jsonb, '[{"key":"weight_kg","label":"الوزن كجم","type":"number","required":true,"step":0.01,"min":1},{"key":"duration_hours","label":"المدة بالساعات","type":"number","required":true,"step":0.01,"min":0},{"key":"activity_factor","label":"معامل النشاط","type":"number","required":true,"step":0.01,"min":0,"defaultValue":6}]'::jsonb, '[{"key":"weight_kg","label":"Weight kg","type":"number","required":true,"step":0.01,"min":1},{"key":"duration_hours","label":"Duration hours","type":"number","required":true,"step":0.01,"min":0},{"key":"activity_factor","label":"Activity factor","type":"number","required":true,"step":0.01,"min":0,"defaultValue":6}]'::jsonb, 'احسب النتيجة', 'Calculate', 4096, false),
  ('fitness-tools', 'training-consistency-rate-calculator', 'حاسبة الالتزام بالتمرين', 'Training Consistency Rate Calculator', 'احسب نسبة الجلسات المكتملة.', 'Calculate completed workout rate.', '{"expression":"completed_sessions / planned_sessions * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نسبة الالتزام","resultLabelEn":"Consistency rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"completed_sessions","label":"الجلسات المكتملة","type":"number","required":true,"step":0.01,"min":0},{"key":"planned_sessions","label":"الجلسات المخططة","type":"number","required":true,"step":0.01,"min":1}]'::jsonb, '[{"key":"completed_sessions","label":"Completed sessions","type":"number","required":true,"step":0.01,"min":0},{"key":"planned_sessions","label":"Planned sessions","type":"number","required":true,"step":0.01,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 4097, false),
  ('fitness-tools', 'swimming-pace-calculator', 'حاسبة وتيرة السباحة', 'Swimming Pace Calculator', 'احسب الزمن لكل 100 متر.', 'Calculate time per 100 meters.', '{"expression":"total_minutes / distance_meters * 100","outputUnitAr":" دقيقة/100م","outputUnitEn":" min/100m","resultLabelAr":"وتيرة السباحة","resultLabelEn":"Swimming pace","decimals":2,"showEquation":true}'::jsonb, '[{"key":"total_minutes","label":"المدة بالدقائق","type":"number","required":true,"step":0.01,"min":0},{"key":"distance_meters","label":"المسافة بالمتر","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"total_minutes","label":"Total minutes","type":"number","required":true,"step":0.01,"min":0},{"key":"distance_meters","label":"Distance meters","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 4098, false),
  ('fitness-tools', 'weekly-distance-goal-progress-calculator', 'حاسبة تقدم هدف المسافة الأسبوعي', 'Weekly Distance Goal Progress Calculator', 'احسب نسبة التقدم نحو هدف المسافة.', 'Calculate progress toward weekly distance goal.', '{"expression":"completed_distance / goal_distance * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"تقدم الهدف","resultLabelEn":"Goal progress","decimals":2,"showEquation":true}'::jsonb, '[{"key":"completed_distance","label":"المسافة المكتملة","type":"number","required":true,"step":0.01,"min":0},{"key":"goal_distance","label":"المسافة المستهدفة","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"completed_distance","label":"Completed distance","type":"number","required":true,"step":0.01,"min":0},{"key":"goal_distance","label":"Goal distance","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 4099, false);

do $$
declare
  v_count integer;
  v_duplicates integer;
begin
  select count(*) into v_count from wave4_formula_tool_seed;
  if v_count <> 100 then
    raise exception 'WAVE4_TOOL_COUNT_MISMATCH:%', v_count;
  end if;

  select count(*) - count(distinct slug)
  into v_duplicates
  from wave4_formula_tool_seed;

  if v_duplicates <> 0 then
    raise exception 'WAVE4_DUPLICATE_SLUGS:%', v_duplicates;
  end if;
end;
$$;

insert into public.tools(
  slug, title_ar, title_en, short_description, category_id, engine_type,
  input_schema, output_schema, runtime_config, pricing_mode, fixed_points,
  minimum_points, requires_auth, is_featured, is_active, sort_order,
  seo_title, seo_description
)
select
  seed.slug,
  seed.title_ar,
  seed.title_en,
  seed.description_ar,
  category.id,
  'formula',
  jsonb_build_object('submitLabel', seed.submit_ar, 'fields', seed.input_fields),
  jsonb_build_object('type', 'number', 'format', 'runtime'),
  seed.runtime_config,
  'free',
  0,
  0,
  false,
  seed.is_featured,
  true,
  seed.sort_order,
  seed.title_ar || ' مجانًا | أمبراطورية الويب',
  seed.description_ar
from wave4_formula_tool_seed seed
join public.categories category on category.slug = seed.category_slug
on conflict (slug) do update set
  title_ar = excluded.title_ar,
  title_en = excluded.title_en,
  short_description = excluded.short_description,
  category_id = excluded.category_id,
  engine_type = excluded.engine_type,
  input_schema = excluded.input_schema,
  output_schema = excluded.output_schema,
  runtime_config = excluded.runtime_config,
  pricing_mode = excluded.pricing_mode,
  fixed_points = excluded.fixed_points,
  minimum_points = excluded.minimum_points,
  requires_auth = excluded.requires_auth,
  is_featured = excluded.is_featured,
  is_active = excluded.is_active,
  sort_order = excluded.sort_order,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  updated_at = now();

insert into public.tool_translations(
  tool_id, locale_id, title, short_description, seo_title, seo_description,
  prompt_template_override
)
select
  tool.id,
  locale.id,
  case when locale.code = 'ar' then seed.title_ar else seed.title_en end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  case
    when locale.code = 'ar' then seed.title_ar || ' مجانًا | أمبراطورية الويب'
    else seed.title_en || ' Free | Web Empire'
  end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  null
from wave4_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id) do update set
  title = excluded.title,
  short_description = excluded.short_description,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  prompt_template_override = null,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  field.value ->> 'key',
  field.value ->> 'label',
  nullif(field.value ->> 'placeholder', ''),
  nullif(field.value ->> 'helpText', ''),
  field.value -> 'options'
from wave4_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
cross join lateral jsonb_array_elements(
  case when locale.code = 'ar' then seed.input_fields else seed.english_fields end
) field(value)
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  placeholder = excluded.placeholder,
  help_text = excluded.help_text,
  options = excluded.options,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  '__submit__',
  case when locale.code = 'ar' then seed.submit_ar else seed.submit_en end,
  null, null, null
from wave4_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  updated_at = now();

do $$
declare
  r record;
begin
  for r in
    select
      category.slug,
      count(tool.id) filter (where tool.is_active) as active_tools
    from public.categories category
    left join public.tools tool on tool.category_id = category.id
    where category.slug in (
    'home-tools',
    'retail-tools',
    'manufacturing-tools',
    'project-management-tools',
    'hospitality-tools',
    'insurance-tools',
    'energy-tools',
    'cybersecurity-tools',
    'photography-tools',
    'fitness-tools'
    )
    group by category.slug
  loop
    if r.active_tools < 5 or r.active_tools > 50 then
      raise exception 'CATEGORY_TOOL_RANGE_VIOLATION:%:%', r.slug, r.active_tools;
    end if;
  end loop;
end;
$$;

commit;

